<?php
namespace Database\Seeders;
use Illuminate\Database\Seeder; use Illuminate\Support\Facades\Hash; use Illuminate\Support\Facades\DB;
class DatabaseSeeder extends Seeder { public function run():void { $now=now(); $jur=DB::table('jurusans')->insertGetId(['nama_jurusan'=>'Desain Komunikasi Visual','kode_jurusan'=>'DKV','created_at'=>$now,'updated_at'=>$now]);$rom=DB::table('rombels')->insertGetId(['nama_rombel'=>'1','created_at'=>$now,'updated_at'=>$now]);$kelas=DB::table('kelas_aktifs')->insertGetId(['tingkat'=>10,'jurusan_id'=>$jur,'rombel_id'=>$rom,'nama_kelas'=>'10 DKV 1','created_at'=>$now,'updated_at'=>$now]); foreach([['superadmin','Super Admin','superadmin@cbt.local','SuperAdmin',null],['admin','Administrator','admin@cbt.local','Admin',null],['guru','Guru Demo','guru@cbt.local','Guru',null],['pengawas','Pengawas Demo','pengawas@cbt.local','Pengawas',null],['siswa','Siswa Demo','siswa@cbt.local','Siswa',$kelas]] as $u) DB::table('users')->insert(['username'=>$u[0],'name'=>$u[1],'email'=>$u[2],'password'=>Hash::make($u[0].'123'),'role'=>$u[3],'kelas_aktif_id'=>$u[4],'status_kehadiran'=>'hadir','created_at'=>$now,'updated_at'=>$now]); $guru=DB::table('users')->where('username','guru')->value('id');$mapel=DB::table('mata_pelajarans')->insertGetId(['kode_mapel'=>'MTK','nama_mapel'=>'Matematika','created_at'=>$now,'updated_at'=>$now]);$paket=DB::table('paket_soals')->insertGetId(['mata_pelajaran_id'=>$mapel,'pembuat_user_id'=>$guru,'judul'=>'Latihan Matematika','status'=>'ready','created_at'=>$now,'updated_at'=>$now]); foreach([['Berapakah hasil dari 2 + 2?',['3','4','5','6'],1],['Berapakah hasil dari 5 x 3?',['8','10','15','20'],2],['Berapakah akar kuadrat dari 81?',['7','8','9','10'],2],['Berapakah hasil dari 100 dibagi 4?',['20','25','30','40'],1]] as $i=>$q){$soal=DB::table('bank_soals')->insertGetId(['paket_soal_id'=>$paket,'urutan'=>$i+1,'tipe_soal'=>'PG','pertanyaan'=>$q[0],'bobot_nilai'=>25,'created_at'=>$now,'updated_at'=>$now]);foreach(['A','B','C','D'] as $x=>$kode) DB::table('opsi_jawabans')->insert(['bank_soal_id'=>$soal,'kode'=>$kode,'teks_opsi'=>$q[1][$x],'is_benar'=>$x===$q[2],'created_at'=>$now,'updated_at'=>$now]);} $master=DB::table('master_ujians')->insertGetId(['judul'=>'Latihan Matematika','paket_soal_id'=>$paket,'tampilkan_nilai_akhir'=>true,'hasil_visibilitas'=>'instant','created_at'=>$now,'updated_at'=>$now]);$jadwal=DB::table('jadwal_ujians')->insertGetId(['master_ujian_id'=>$master,'waktu_mulai'=>now()->subDay(),'waktu_selesai'=>now()->addDays(30),'durasi_menit'=>60,'gunakan_token'=>true,'token'=>'LATIHAN','created_at'=>$now,'updated_at'=>$now]);DB::table('jadwal_ujian_kelas')->insert(['jadwal_ujian_id'=>$jadwal,'kelas_aktif_id'=>$kelas]); $this->call(RolePermissionSeeder::class); }}